parameters.script:
const items = $input.all();
const nodes = [];
const edges = [];

for (const item of items) {
  const nome = item.json.Nome || item.json.name || '';
  const cargo = item.json.Cargo || item.json.role || '';
  const gestor = item.json.Gestor || item.json.manager || '';
  const area = item.json Área || item.json.area || 'Geral';

  nodes.push({
    id: nome,
    data: {
      label: nome + '\n' + cargo,
      area: area
    }
  });

  if (gestor) {
    edges.push({
      id: gestor + '-' + nome,
      source: gestor,
      target: nome
    });
  }
}

return [{ json: { nodes, edges } }];
